logger = logging.getLogger(__name__)


def _sanitize_log_msg(msg: str) -> str:
    """Удаляет токены из логов."""
    if not msg:
        return msg
    import re
    # Telegram bot tokens
    msg = re.sub(r"\b\d{8,10}:[A-Za-z0-9_-]{35}\b", "[TOKEN]", msg)
    # API keys
    msg = re.sub(r"\b(gsk_|sk-|AIza)[A-Za-z0-9_-]{20,}\b", "[API_KEY]", msg)
    # Database URLs (маскируем пароль)
    msg = re.sub(r"(mysql|postgres)://[^:]+:[^@]+@", r"\1://user:***@", msg)
    return msg

_AI_HISTORY_MAX = 20
_CACHE_MAX_AGE_HOURS = 48
_tls = threading.local()

# One-time schema init: avoid DDL on every request
_SCHEMA_INIT_DONE = False
_SCHEMA_INIT_LOCK = threading.Lock()
_PING_THROTTLE_SEC = 60  # only ping connection at most once per minute

# TTL caches for hot path (30–60s), reduce DB round-trips
_CACHE_TTL_SEC = 60
_PREFIX_CACHE: Dict[int, Tuple[float, Optional[str]]] = {}
_ALIAS_CACHE: Dict[Tuple[int, str], Tuple[float, Optional[str]]] = {}
_IS_USER_CONFIRMED_CACHE: Dict[int, Tuple[float, bool]] = {}
_AI_MODE_CACHE: Dict[int, Tuple[float, Optional[Dict[str, Any]]]] = {}
_CACHE_MAX_ENTRIES = 2000


def _get_conn() -> Optional[pymysql.Connection]:
    return getattr(_tls, "conn", None)


def _set_conn(conn: Optional[pymysql.Connection]) -> None:
    _tls.conn = conn


def _get_last_ping() -> float:
    return getattr(_tls, "last_ping", 0.0)


def _set_last_ping(t: float) -> None:
    _tls.last_ping = t


def _cache_evict_if_needed(cache: Dict, max_entries: int = _CACHE_MAX_ENTRIES) -> None:
    if len(cache) <= max_entries:
        return
    now = time.time()
    expired = [k for k, (ts, _) in list(cache.items()) if (now - ts) > _CACHE_TTL_SEC]
    for k in expired[: max_entries // 2]:
        cache.pop(k, None)


def _parse_mysql_url(url: str) -> dict:
    u = urlparse(url)
    path = (u.path or "").strip("/")
    return {
        "host": u.hostname or "localhost",
        "port": int(u.port or 3306),
        "user": u.username or "root",
        "password": u.password or "",
        "database": path or "your_database",
        "charset": "utf8mb4",
    }


def _get_url() -> str:
    return (os.getenv("DATABASE_URL") or "").strip()


def _connect() -> pymysql.Connection:
    url = _get_url()
    if not url:
        raise RuntimeError("DATABASE_URL not set")
    params = _parse_mysql_url(url)
    params["connect_timeout"] = 10
    conn = pymysql.connect(**params)
    _set_conn(conn)
    return conn


def _close_conn() -> None:
    conn = _get_conn()
    if conn:
        try:
            conn.close()
        except Exception:
            pass
        _set_conn(None)


_CONN_ERRORS = (
    pymysql.err.OperationalError,
    pymysql.err.InterfaceError,
    ValueError,
)


def _retry_on_conn_error(fn: Callable) -> Callable:
    """Повтор операции при ошибке соединения (Lost connection, read of closed file)."""
    @functools.wraps(fn)
    def wrapper(*args, **kwargs):
        for attempt in range(2):
            try:
                return fn(*args, **kwargs)
            except _CONN_ERRORS as e:
                if attempt == 0:
                    _close_conn()
                    logger.info("MySQL reconnect after: %s", _sanitize_log_msg(str(e)))
                    continue
                logger.warning("db: %s", _sanitize_log_msg(str(e)))
                raise
        return None  # unreachable
    return wrapper


@contextmanager
def _conn_cursor(commit: bool = True):
    """Контекстный менеджер для курсора. commit=False для read-only (не делаем COMMIT после SELECT)."""
    import time as _time
    url = _get_url()
    if not url:
        raise RuntimeError("DATABASE_URL not set")
    conn = _get_conn()
    if conn is None:
        _connect()
        conn = _get_conn()
    else:
        now = _time.time()
        if (now - _get_last_ping()) >= _PING_THROTTLE_SEC:
            try:
                conn.ping(reconnect=True)
                _set_last_ping(now)
            except Exception:
                _close_conn()
                _connect()
                conn = _get_conn()
                _set_last_ping(_time.time())
    cur = conn.cursor(pymysql.cursors.DictCursor)
    try:
        yield cur
        if commit:
            conn.commit()
    except Exception as e:
        if conn:
            try:
                conn.rollback()
            except Exception:
                pass
        if isinstance(e, _CONN_ERRORS):
            _close_conn()
        logger.warning("db: %s", _sanitize_log_msg(str(e)))
        raise
    finally:
        cur.close()


