def _ensure_init():
    global _SCHEMA_INIT_DONE
    if _SCHEMA_INIT_DONE:
        return
    with _SCHEMA_INIT_LOCK:
        if _SCHEMA_INIT_DONE:
            return
        try:
            _init_schema()
            _SCHEMA_INIT_DONE = True
        except Exception as e:
            logger.exception("schema init: %s", e)
            raise


