# --- user prefix (кастомный префикс для каждого пользователя) ---


@_retry_on_conn_error
def prefix_get(user_id: int) -> Optional[str]:
    now = time.time()
    cached = _PREFIX_CACHE.get(user_id)
    if cached and (now - cached[0]) < _CACHE_TTL_SEC:
        return cached[1]
    _ensure_init()
    with _conn_cursor(commit=False) as cur:
        cur.execute("SELECT prefix FROM axs_user_prefix WHERE user_id = %s", (user_id,))
        row = cur.fetchone()
        val = (row["prefix"] or "").strip() if row else None
    _cache_evict_if_needed(_PREFIX_CACHE)
    _PREFIX_CACHE[user_id] = (now, val)
    return val


@_retry_on_conn_error
def prefix_set(user_id: int, prefix: str) -> None:
    p = (prefix or "").strip()[:32]
    if not p or not p.startswith("."):
        return
    _ensure_init()
    with _conn_cursor() as cur:
        cur.execute(
            "INSERT INTO axs_user_prefix (user_id, prefix) VALUES (%s, %s) ON DUPLICATE KEY UPDATE prefix = VALUES(prefix)",
            (user_id, p),
        )
    _PREFIX_CACHE.pop(user_id, None)


@_retry_on_conn_error
def prefix_reset(user_id: int) -> bool:
    _ensure_init()
    with _conn_cursor() as cur:
        cur.execute("DELETE FROM axs_user_prefix WHERE user_id = %s", (user_id,))
        ok = cur.rowcount > 0
    if ok:
        _PREFIX_CACHE.pop(user_id, None)
    return ok


