@_retry_on_conn_error
def user_settings_get_seen_date_format(user_id: int) -> str:
    """Формат даты для команды seen: short, long, relative. По умолчанию short. Кэш 60s."""
    uid = int(user_id)
    now = time.time()
    cached = _SEEN_FORMAT_CACHE.get(uid)
    if cached and (now - cached[0]) < _SEEN_FORMAT_CACHE_TTL_SEC:
        return cached[1]
    _ensure_init()
    with _conn_cursor(commit=False) as cur:
        cur.execute(
            "SELECT seen_date_format FROM axs_user_settings WHERE user_id = %s",
            (uid,),
        )
        row = cur.fetchone()
    v = "short"
    if row and row.get("seen_date_format"):
        candidate = (row["seen_date_format"] or "").strip().lower()
        if candidate in ("short", "long", "relative"):
            v = candidate
    _SEEN_FORMAT_CACHE[uid] = (time.time(), v)
    return v


