# --- Telegram StringSession, хранение в axs_web_sessions ---


@_retry_on_conn_error
def web_get_latest_active_session() -> Optional[Dict[str, Any]]:
    """
    Возвращает последнюю активную строку сессии Telegram из axs_web_sessions.
    Используется ботом при старте: берём только is_active=1 и только для одобренных пользователей.
    """
    _ensure_init()
    with _conn_cursor() as cur:
        cur.execute(
            """
            SELECT s.id,
                   s.encrypted_session,
                   s.user_id,
                   s.last_used_at,
                   u.telegram_id,
                   u.username
            FROM axs_web_sessions AS s
            JOIN axs_web_users AS u ON u.id = s.user_id
            WHERE s.is_active = 1 AND u.is_approved = 1
            ORDER BY s.last_used_at DESC
            LIMIT 1
            """
        )
        row = cur.fetchone()
        if not row:
            return None
        now = datetime.utcnow()
        cur.execute(
            "UPDATE axs_web_sessions SET last_used_at = %s WHERE id = %s",
            (now, row["id"]),
        )
        row["last_used_at"] = now
        return row



