def user_ensure_first_is_admin(telegram_id: int) -> None:
    """Если в таблице ровно 1 пользователь — автоматически назначает его admin."""
    _ensure_init()
    with _conn_cursor() as cur:
        cur.execute("SELECT COUNT(*) AS cnt FROM axs_web_users")
        row = cur.fetchone()
        if row and int(row.get("cnt") or 0) == 1:
            cur.execute(
                "UPDATE axs_web_users SET role = 'admin' WHERE telegram_id = %s",
                (str(telegram_id),),
            )